SELECT c.customerid, AVG(od.quantity * od.unitprice) AS avg_order_value FROM customers AS c JOIN orders AS o ON c.customerid = o.customerid JOIN "order details" AS od ON o.orderid = od.orderid JOIN products AS p ON od.productid = p.productid JOIN categories AS cat ON p.categoryid = cat.categoryid WHERE (c.region IS NOT NULL) AND (cat.categoryname = 'Beverages') AND (strftime('%Y', o.orderdate) = '1997') GROUP BY c.customerid HAVING (AVG(od.quantity * od.unitprice) > 100)
